#!/bin/bash\n\n# Research Portal Backend - Startup Script\n# This script starts the FastAPI backend on port 8000\n# Usage: bash start_backend.sh\n\necho \"🚀 Starting Research Portal Backend...\"\necho \"\"\n\ncd \"$(dirname \"$0\")\" || exit\n\n# Use Python 3.11 with installed packages\nPYTHON_PATH=\"/Library/Frameworks/Python.framework/Versions/3.11/bin/python3\"\n\n# Check if Python is available\nif [ ! -f \"$PYTHON_PATH\" ]; then\n    echo \"❌ Error: Python 3.11 not found at $PYTHON_PATH\"\n    echo \"Please install Python 3.11 or update the path in this script.\"\n    exit 1\nfi\n\necho \"✅ Using Python: $PYTHON_PATH\"\necho \"✅ Version: $($PYTHON_PATH --version)\"\necho \"\"\n\n# Start the backend\necho \"📡 Starting Uvicorn server...\"\necho \"Backend will be available at: http://127.0.0.1:8000\"\necho \"API Documentation: http://127.0.0.1:8000/docs\"\necho \"\"\necho \"Press Ctrl+C to stop the server\"\necho \"\"\n\n$PYTHON_PATH -m uvicorn app.main:app --reload --host 127.0.0.1 --port 8000\n